// Register a bean programmatically before context refresh
// Useful for dynamic bean registration based on runtime conditions

@Configuration
public class DynamicBeanConfig implements BeanDefinitionRegistryPostProcessor {

    @Override
    public void postProcessBeanDefinitionRegistry(BeanDefinitionRegistry registry) {
        // Build a BeanDefinition from scratch
        GenericBeanDefinition def = new GenericBeanDefinition();
        def.setBeanClass(PaymentProcessor.class);
        def.setScope(BeanDefinition.SCOPE_SINGLETON);
        def.getConstructorArgumentValues()
            .addGenericArgumentValue("https://payment-gateway.example.com");
        def.setInitMethodName("connect");
        def.setDestroyMethodName("disconnect");
        def.setPrimary(true);

        registry.registerBeanDefinition("paymentProcessor", def);
    }

    @Override
    public void postProcessBeanFactory(ConfigurableListableBeanFactory beanFactory) {
        // Inspect or modify existing bean definitions
        String[] names = beanFactory.getBeanDefinitionNames();
        for (String name : names) {
            BeanDefinition bd = beanFactory.getBeanDefinition(name);
            if (bd.getBeanClassName() != null &&
                bd.getBeanClassName().startsWith("com.example.legacy")) {
                bd.setLazyInit(true); // make all legacy beans lazy
            }
        }
    }
}

