    }

    @Override
    public void destroy() throws Exception {
        // Orderly shutdown — allow in-flight tasks to finish
        executor.shutdown();
        if (!executor.awaitTermination(30, TimeUnit.SECONDS)) {
            executor.shutdownNow();
        }
    }

