        // Safe to send email — order is persisted
        emailService.sendConfirmation(event.getCustomerId());
    }

    // BEFORE_COMMIT — runs before commit, inside the transaction
    @TransactionalEventListener(phase = TransactionPhase.BEFORE_COMMIT)
    public void beforeCommit(OrderPlacedEvent event) {
        auditService.prepareAuditEntry(event);
    }

    // AFTER_ROLLBACK — diagnostic / cleanup on failure
