@Aspect
@Component
public class SecurityAspect {

    @Before("execution(* com.example.service.*.*(..)) && @annotation(secured)")
    public void checkSecurity(JoinPoint joinPoint, Secured secured) {
        // joinPoint.getArgs() — method arguments
        // joinPoint.getSignature() — method name and declaring class
        // joinPoint.getTarget() — the target bean instance
        String currentUser = SecurityContextHolder.getContext()
            .getAuthentication().getName();
        if (!hasRequiredRole(currentUser, secured.role())) {
            throw new AccessDeniedException(
                "User " + currentUser + " lacks role " + secured.role());
        }
    }
}

@Aspect
@Component
public class OperationalAspect {

    private static final Logger log = LoggerFactory.getLogger(OperationalAspect.class);

    // Timing advice
    @Around("execution(* com.example.service..*(..))")
    public Object measureExecutionTime(ProceedingJoinPoint pjp) throws Throwable {
        long start = System.currentTimeMillis();
        try {
            Object result = pjp.proceed(); // invoke the target method
            long elapsed = System.currentTimeMillis() - start;
            log.info("{} completed in {}ms", pjp.getSignature().getName(), elapsed);
            return result;
        } catch (Throwable ex) {
            long elapsed = System.currentTimeMillis() - start;
            log.error("{} failed after {}ms: {}",
                pjp.getSignature().getName(), elapsed, ex.getMessage());
            throw ex; // rethrow — @Around must rethrow or handle all exceptions
        }
    }

    // Modify return value
    @Around("@annotation(cacheable)")
    public Object cacheResult(ProceedingJoinPoint pjp, Cacheable cacheable) throws Throwable {
        String key = buildKey(pjp, cacheable);
        Object cached = cacheService.get(key);
        if (cached != null) return cached;
        Object result = pjp.proceed();
        cacheService.put(key, result, cacheable.ttl());
        return result;
    }
}

