    public void serviceLayer() {}

    @Pointcut("execution(* com.example.repository..*(..))")
    public void repositoryLayer() {}

    @Pointcut("@annotation(org.springframework.transaction.annotation.Transactional)")
    public void transactionalMethod() {}

    @Pointcut("execution(public * *(..))")
    public void publicMethods() {}

    // Composed: public methods in service layer
    @Pointcut("serviceLayer() && publicMethods()")
    public void publicServiceMethods() {}

    // execution syntax:
    // execution([access] returnType [class.]method(params) [throws])
    //
    // * com.example.service.*.*(..) =
    //   any return type, service package (shallow), any class, any method, any args
    //
    // * com.example.service..*.*(..)
    //   .. means service package AND all sub-packages
    //
    // execution(public String com.example.*(String, ..))
    //   public String-returning methods in com.example, first arg String, rest any
}

// 1. Define the custom annotation
@Target(ElementType.METHOD)
@Retention(RetentionPolicy.RUNTIME)
public @interface Audited {
    String action() default "";
    boolean logArgs() default false;
}

// 2. Apply to methods
@Service
public class UserService {

    @Audited(action = "CREATE_USER", logArgs = true)
    public User create(CreateUserRequest request) {
        return userRepository.save(new User(request));
    }

    @Audited(action = "DELETE_USER")
    public void delete(Long userId) {
        userRepository.deleteById(userId);
    }
}

// 3. Implement the aspect
@Aspect
@Component
public class AuditAspect {

    private final AuditEventRepository auditRepo;

    public AuditAspect(AuditEventRepository auditRepo) {
        this.auditRepo = auditRepo;
    }

    @Around("@annotation(audited)")
    public Object audit(ProceedingJoinPoint pjp, Audited audited) throws Throwable {
        String user = SecurityContextHolder.getContext().getAuthentication().getName();
        Object[] args = audited.logArgs() ? pjp.getArgs() : new Object[0];
        try {
            Object result = pjp.proceed();
            auditRepo.save(new AuditEvent(user, audited.action(), "SUCCESS", args));
            return result;
        } catch (Throwable ex) {
            auditRepo.save(new AuditEvent(user, audited.action(), "FAILURE", args));
            throw ex;
        }
    }
}

// When multiple aspects apply to the same JoinPoint,
// @Order controls which aspect's advice runs first (outermost = lowest value)

@Aspect
@Component
@Order(1) // Outermost — enters first, exits last
public class TransactionAspect {
    @Around("@annotation(transactional)")
    public Object wrapInTransaction(ProceedingJoinPoint pjp,
                                    Transactional transactional) throws Throwable {
        // begin transaction
        Object result = pjp.proceed();
        // commit transaction
        return result;
    }
}

@Aspect
@Component
@Order(2) // Inside TransactionAspect, outside SecurityAspect
public class LoggingAspect {
    @Around("execution(* com.example.service.*.*(..))")
    public Object log(ProceedingJoinPoint pjp) throws Throwable {
        log.debug("Entering: {}", pjp.getSignature());
        Object result = pjp.proceed();
        log.debug("Exiting: {}", pjp.getSignature());
        return result;
    }
}

@Aspect
@Component
@Order(3) // Innermost — closest to target method
public class SecurityAspect {
    @Before("execution(* com.example.service.*.*(..))")
    public void checkAuth(JoinPoint jp) { ... }
}

// Execution order for a matched method:
// TransactionAspect.before → LoggingAspect.before → SecurityAspect.before
//   → target method
// SecurityAspect.after → LoggingAspect.after → TransactionAspect.after
